/**
 * FFI-facing error variants. Stays narrow so consumers can match
 * exhaustively from Swift without surprises. All variants are
 * constructed from inner `SyncError`s via the `From` impl below.
 */
public enum FfiSyncError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    /**
     * The bytes the host handed us don't decode as a valid pairing
     * code (bad base64, bad postcard, future version, etc.).
     */
    case InvalidPairingCode(
        /**
         * Free-text reason; safe to surface to users.
         */message: String
    )
    /**
     * A wrapped error we couldn't more usefully classify yet.
     */
    case Other(
        /**
         * Free-text reason.
         */message: String
    )

    

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

#if compiler(>=6)
extension FfiSyncError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiSyncError: FfiConverterRustBuffer {
    typealias SwiftType = FfiSyncError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiSyncError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .InvalidPairingCode(
            message: try FfiConverterString.read(from: &buf)
            )
        case 2: return .Other(
            message: try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: FfiSyncError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .InvalidPairingCode(message):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .Other(message):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(message, into: &buf)
            
        }
    }
}


